package br.com.portfolio.ecommerce.order.infrastructure.persistence;
import br.com.portfolio.ecommerce.order.application.port.out.OrderRepository; import br.com.portfolio.ecommerce.order.domain.*; import br.com.portfolio.ecommerce.shared.domain.Money; import org.springframework.stereotype.Repository; import java.lang.reflect.*; import java.util.*;
@Repository public class OrderRepositoryAdapter implements OrderRepository { private final OrderJpaRepository repo; public OrderRepositoryAdapter(OrderJpaRepository repo){this.repo=repo;} public Optional<Order> findByIdempotencyKey(String key){return repo.findByIdempotencyKey(key).map(this::toDomain);} public Optional<Order> findById(UUID id){return repo.findById(id).map(this::toDomain);} public Order save(Order o){ return toDomain(repo.save(toEntity(o))); }
 private OrderJpaEntity toEntity(Order o){ var e=new OrderJpaEntity(); e.id=o.id(); e.customerId=o.customerId(); e.status=o.status(); e.subtotal=o.subtotal().amount(); e.discount=o.discount().amount(); e.shipping=o.shipping().amount(); e.total=o.total().amount(); e.idempotencyKey=o.idempotencyKey(); e.createdAt=o.createdAt(); for(var it:o.items()){ var ie=new OrderItemJpaEntity(); ie.productId=it.productId(); ie.productName=it.productName(); ie.quantity=it.quantity(); ie.unitPrice=it.unitPrice().amount(); ie.order=e; e.items.add(ie);} return e; }
 private Order toDomain(OrderJpaEntity e){ var items=e.items.stream().map(i->new OrderItem(i.productId,i.productName,i.quantity,new Money(i.unitPrice))).toList(); var o=Order.checkout(e.customerId,items,new Money(e.discount),new Money(e.shipping),e.idempotencyKey); set(o,"id",e.id); set(o,"status",e.status); set(o,"createdAt",e.createdAt); return o; }
 private void set(Object target,String field,Object value){ try{ Field f=target.getClass().getDeclaredField(field); f.setAccessible(true); f.set(target,value);}catch(Exception ex){throw new IllegalStateException(ex);} }
}
